"use client";

import Link from "next/link";
import { motion } from "framer-motion";
import { ThemeToggle } from "./ThemeToggle";
import { Command } from "lucide-react";
import { useState, useEffect } from "react";
import { CommandMenu } from "./CommandMenu";

const links = [
    { name: "Home", path: "#home" },
    { name: "About", path: "#about" },
    { name: "Work", path: "#projects" },
    { name: "Blogs", path: "#blog" },
];

export function Navbar() {
    const [isCommandOpen, setIsCommandOpen] = useState(false);

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if ((e.metaKey || e.ctrlKey) && e.key === "k") {
                e.preventDefault();
                setIsCommandOpen((prev) => !prev);
            }
        };

        window.addEventListener("keydown", handleKeyDown);
        return () => window.removeEventListener("keydown", handleKeyDown);
    }, []);

    return (
        <>
            <motion.header
                initial={{ y: -100, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                transition={{ duration: 0.8, ease: "easeOut" }}
                className="fixed top-0 left-0 right-0 z-50 px-6 py-6"
            >
                <div className="max-w-[1400px] mx-auto flex items-center justify-between">
                    {/* Left: Logo & Title */}
                    <div className="flex items-center space-x-4">
                        <div className="text-2xl font-serif italic font-bold">PM</div>
                        <div className="hidden sm:flex flex-col">
                            <span className="text-[10px] tracking-widest font-semibold text-neutral-500 dark:text-neutral-400">CREATIVE ENGINEER</span>
                            <div className="flex items-center space-x-1.5 mt-0.5">
                                <span className="w-1.5 h-1.5 rounded-full bg-green-500 animate-[pulse_2s_ease-in-out_infinite]"></span>
                                <span className="text-[10px] tracking-widest font-semibold text-green-600 dark:text-green-500">BUILDING THE FUTURE</span>
                            </div>
                        </div>
                    </div>

                    {/* Center: Navigation Pill */}
                    <nav className="hidden md:flex items-center px-1.5 py-1.5 rounded-full bg-neutral-100/90 dark:bg-[#111111]/90 backdrop-blur-md border border-neutral-200 dark:border-[#222] shadow-sm transition-colors">
                        <ul className="flex items-center">
                            {links.map((link) => (
                                <li key={link.name}>
                                    <Link
                                        href={link.path}
                                        className="px-5 py-2 text-sm font-medium text-neutral-600 dark:text-neutral-400 hover:text-black dark:hover:text-white transition-colors rounded-full hover:bg-black/5 dark:hover:bg-white/5"
                                    >
                                        {link.name}
                                    </Link>
                                </li>
                            ))}
                            <li>
                                <button className="px-5 py-2 text-sm font-medium text-neutral-600 dark:text-neutral-400 hover:text-black dark:hover:text-white transition-colors rounded-full hover:bg-black/5 dark:hover:bg-white/5 flex items-center space-x-1">
                                    <span>More</span>
                                    <svg width="10" height="6" viewBox="0 0 10 6" fill="none" xmlns="http://www.w3.org/2000/svg" className="mt-0.5 opacity-50">
                                        <path d="M1 1L5 5L9 1" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
                                    </svg>
                                </button>
                            </li>
                            <div className="w-[1px] h-4 mx-2 bg-neutral-300 dark:bg-[#333]" />
                            <div className="px-2 flex items-center justify-center">
                                <ThemeToggle />
                            </div>
                            <li className="ml-1">
                                <Link
                                    href="#contact"
                                    className="px-5 py-2 text-sm font-medium text-white bg-[#111] dark:text-[#111] dark:bg-[#ededed] rounded-full hover:bg-black dark:hover:bg-white transition-colors"
                                >
                                    Book a Call
                                </Link>
                            </li>
                        </ul>
                    </nav>

                    {/* Right: Command Icon */}
                    <button
                        onClick={() => setIsCommandOpen(true)}
                        aria-label="Command Menu"
                        className="w-10 h-10 rounded-full border border-neutral-200 dark:border-[#333] flex items-center justify-center text-neutral-600 dark:text-neutral-400 hover:text-black dark:hover:text-white hover:bg-neutral-100 dark:hover:bg-[#222] transition-colors"
                    >
                        <Command className="w-4 h-4" />
                    </button>
                </div>
            </motion.header>

            <CommandMenu isOpen={isCommandOpen} onClose={() => setIsCommandOpen(false)} />
        </>
    );
}
